,p_tool_type=>'NATIVE_RETRIEVE_DATA'
,p_execution_point=>'AUGMENT_SYSTEM_PROMPT'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'language', 'PLSQL',
  'plsql_code', wwv_flow_string.join(wwv_flow_t_varchar2(
    'DECLARE',
    'L_SCHOOL_NAME HIGHSCHOOLS.SCHOOL_NAME%TYPE;',
    'L_PROMPT CLOB;',
    'BEGIN',
    '    SELECT SCHOOL_NAME INTO L_SCHOOL_NAME ',
    '    FROM HIGHSCHOOLS WHERE ID = :P3_SCHOOL_ID;',
    '    L_PROMPT :=',
    '        q''[',
    '        Parent Name : ]''|| :P3_PARENT_NAME||chr(10)||chr(13) ||q''[',
    '        Applicant Name : ]''|| :P3_STUDENT_NAME||chr(10)||chr(13) ||q''[',
    '        School Name : ]''|| initcap(L_SCHOOL_NAME)||chr(10)||chr(13);',
    '',
    '    return L_PROMPT;',
    '',
    'END;')),
  'type', 'FUNCTION_BODY')).to_clob
,p_created_on=>wwv_flow_imp.dz('20260611130818Z')
